+function createToolWithScreenshotter(
+  store: DiffArtifactStore,
+  screenshotter: DiffScreenshotter,
+  defaults = DEFAULT_DIFFS_TOOL_DEFAULTS,
+) {
+  return createDiffsTool({
+    api: createApi(),
